-- satellite_intel 전체 덤프 (RDS에서 추출)
-- MySQL Workbench: File > Open SQL Script 로 열어 실행하면 DB가 통째로 만들어집니다.
SET NAMES utf8mb4;
-- RDS 원본에 zero date('0000-00-00')와 user_id=0이 있어, 기본 strict 모드를 세션에서만 해제한다.
SET SESSION sql_mode = 'NO_AUTO_VALUE_ON_ZERO';
SET FOREIGN_KEY_CHECKS = 0;
CREATE DATABASE IF NOT EXISTS `satellite_intel` DEFAULT CHARACTER SET utf8mb4;
USE `satellite_intel`;

DROP TABLE IF EXISTS `alert`;
CREATE TABLE `alert` (
  `alert_id` bigint NOT NULL AUTO_INCREMENT,
  `change_id` bigint NOT NULL,
  `alert_level` enum('URGENT','IMPORTANT','NOTICE') COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `message` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `alert_status` enum('NEW','CHECKED') COLLATE utf8mb4_unicode_ci DEFAULT 'NEW',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`alert_id`),
  UNIQUE KEY `uq_alert_change` (`change_id`),
  CONSTRAINT `alert_ibfk_1` FOREIGN KEY (`change_id`) REFERENCES `change_event` (`change_id`)
) ENGINE=InnoDB AUTO_INCREMENT=103 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `ally_asset`;
CREATE TABLE `ally_asset` (
  `asset_id` int NOT NULL AUTO_INCREMENT,
  `unit_name` varchar(50) NOT NULL,
  `platform_name` varchar(100) NOT NULL,
  `category` varchar(50) NOT NULL,
  `munition_name` varchar(100) NOT NULL,
  `range_km` decimal(8,2) NOT NULL,
  `effect_radius_m` decimal(8,2) DEFAULT NULL,
  `response_time_min` int NOT NULL,
  `suitable_target_categories` json NOT NULL,
  `notes` text,
  `location_name` varchar(100) DEFAULT NULL,
  `latitude` decimal(9,6) DEFAULT NULL,
  `longitude` decimal(9,6) DEFAULT NULL,
  PRIMARY KEY (`asset_id`),
  UNIQUE KEY `uq_ally_asset_unit_munition` (`unit_name`,`munition_name`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `app_user`;
CREATE TABLE `app_user` (
  `user_id` bigint NOT NULL AUTO_INCREMENT,
  `login_id` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `password_hash` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `role` enum('ANALYST','COMMANDER') COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_active` tinyint(1) DEFAULT '1',
  `log_time` datetime NOT NULL,
  PRIMARY KEY (`user_id`),
  UNIQUE KEY `login_id` (`login_id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `change_event`;
CREATE TABLE `change_event` (
  `change_id` bigint NOT NULL AUTO_INCREMENT,
  `previous_image_id` bigint NOT NULL,
  `current_image_id` bigint NOT NULL,
  `equipment_id` bigint NOT NULL,
  `event_type` enum('NEW','INCREASED','DECREASED','DISAPPEARED','UNCHANGED') COLLATE utf8mb4_unicode_ci NOT NULL,
  `previous_count` int NOT NULL,
  `current_count` int NOT NULL,
  `delta_count` int NOT NULL,
  `summary` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`change_id`),
  KEY `previous_image_id` (`previous_image_id`),
  KEY `current_image_id` (`current_image_id`),
  KEY `equipment_id` (`equipment_id`),
  CONSTRAINT `change_event_ibfk_1` FOREIGN KEY (`previous_image_id`) REFERENCES `image_analysis` (`image_id`),
  CONSTRAINT `change_event_ibfk_2` FOREIGN KEY (`current_image_id`) REFERENCES `image_analysis` (`image_id`),
  CONSTRAINT `change_event_ibfk_3` FOREIGN KEY (`equipment_id`) REFERENCES `equipment` (`equipment_id`)
) ENGINE=InnoDB AUTO_INCREMENT=340 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `commander_decision`;
CREATE TABLE `commander_decision` (
  `report_id` int NOT NULL AUTO_INCREMENT COMMENT '보고서 고유 식별키',
  `commander_id` varchar(50) NOT NULL COMMENT '지휘관 식별자',
  `who_text` varchar(255) DEFAULT NULL COMMENT '적군 부대명 (Who)',
  `when_text` varchar(100) DEFAULT NULL COMMENT '탐지 시간 (When)',
  `where_text` varchar(255) DEFAULT NULL COMMENT '적군 지역 (Where)',
  `what_text` text COMMENT '탐지된 적군 장비 (What)',
  `how_text` text COMMENT '아군 타격 장비 (How)',
  `why_text` text COMMENT '결심 배경 및 목적 (Why)',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '생성 시간',
  PRIMARY KEY (`report_id`)
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='지휘관 결심 보고 테이블';


DROP TABLE IF EXISTS `detection_result`;
CREATE TABLE `detection_result` (
  `detection_id` bigint NOT NULL AUTO_INCREMENT,
  `image_id` bigint NOT NULL,
  `equipment_id` bigint NOT NULL,
  `detected_count` int NOT NULL,
  `avg_confidence` decimal(5,4) NOT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`detection_id`),
  UNIQUE KEY `image_id` (`image_id`,`equipment_id`),
  KEY `equipment_id` (`equipment_id`),
  CONSTRAINT `detection_result_ibfk_1` FOREIGN KEY (`image_id`) REFERENCES `image_analysis` (`image_id`),
  CONSTRAINT `detection_result_ibfk_2` FOREIGN KEY (`equipment_id`) REFERENCES `equipment` (`equipment_id`)
) ENGINE=InnoDB AUTO_INCREMENT=41101 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `equipment`;
CREATE TABLE `equipment` (
  `equipment_id` bigint NOT NULL AUTO_INCREMENT,
  `class_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `threat_level` int NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`equipment_id`),
  UNIQUE KEY `class_name` (`class_name`)
) ENGINE=InnoDB AUTO_INCREMENT=89 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `image_analysis`;
CREATE TABLE `image_analysis` (
  `image_id` bigint NOT NULL AUTO_INCREMENT,
  `asset_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `region_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `region_id` bigint DEFAULT NULL,
  `sensor_type` enum('EO','SAR') COLLATE utf8mb4_unicode_ci NOT NULL,
  `captured_time` datetime NOT NULL,
  `original_image_path` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `result_image_path` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`image_id`),
  KEY `region_id` (`region_id`),
  CONSTRAINT `image_analysis_ibfk_region` FOREIGN KEY (`region_id`) REFERENCES `region` (`region_id`)
) ENGINE=InnoDB AUTO_INCREMENT=16441 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `intel_report`;
CREATE TABLE `intel_report` (
  `report_id` bigint NOT NULL AUTO_INCREMENT,
  `alert_id` bigint NOT NULL,
  `author_id` bigint NOT NULL,
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `summary` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `report_status` enum('DRAFT','DISTRIBUTED') COLLATE utf8mb4_unicode_ci NOT NULL,
  `distributed_at` datetime DEFAULT NULL,
  PRIMARY KEY (`report_id`),
  KEY `alert_id` (`alert_id`),
  KEY `author_id` (`author_id`),
  CONSTRAINT `intel_report_ibfk_1` FOREIGN KEY (`alert_id`) REFERENCES `alert` (`alert_id`),
  CONSTRAINT `intel_report_ibfk_2` FOREIGN KEY (`author_id`) REFERENCES `app_user` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `region`;
CREATE TABLE `region` (
  `region_id` bigint NOT NULL AUTO_INCREMENT,
  `region_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `region_name_en` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `latitude` decimal(10,7) NOT NULL,
  `longitude` decimal(10,7) NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`region_id`),
  UNIQUE KEY `uk_region_name` (`region_name`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


SET FOREIGN_KEY_CHECKS = 1;
