INSERT INTO `ally_asset` (`asset_id`, `unit_name`, `platform_name`, `category`, `munition_name`, `range_km`, `effect_radius_m`, `response_time_min`, `suitable_target_categories`, `notes`, `location_name`, `latitude`, `longitude`) VALUES
(1, '제11전투비행단', 'F-15K', '항공전력', 'KGGB 유도폭탄', 1800.00, 100.00, 15, '[\"기갑표적\", \"차량표적\", \"항공표적\"]', 'GPS/INS 유도 활공폭탄. 투하고도에 따라 사거리 약 47~110km(통상 100km로 표기), CEP 약 3m.', '대구 국제공항', 35.900325, 128.638942),
(2, '제11전투비행단', 'F-15K', '항공전력', '집속탄', 1800.00, 10.00, 15, '[\"차량표적\", \"대인표적\"]', '무유도 투하식 집속탄(자탄 다수 살포)이라 유도무기처럼 스탠드오프 사거리 개념이 없음. 항공기가 목표 상공까지 접근해 투하하므로, 편의상 F-15K 전투행동반경(약 1,800km)을 range_km로 대입한 추정치입니다. 실제로는 방공망 등 위협에 따라 접근 가능 여부가 달라집니다.', '대구 국제공항', 35.900325, 128.638942),
(3, '제1포병여단', 'K9A1', '자주곡사포', '이중목적고폭탄', 60.00, 40.00, 5, '[\"기갑표적\", \"차량표적\", \"항공표적\"]', 'K310 이중목적고폭탄(DPICM) 기준 사거리 36km. 최신 155mm 사거리연장탄 적용 시 최대 45km까지 보고됨.', '양주시 남면', 37.896469, 126.979839),
(4, '제1포병여단', 'K9A1', '자주곡사포', '대전차고폭탄', 45.00, 50.00, 5, '[\"기갑표적\"]', '대전차고폭탄(HEAT)은 통상 K2 전차 등 전차포 주력탄종이며 K9(곡사포)의 표준 운용탄약은 아님. 직사 대전차 교전 기준의 추정 근거리 값(참고용, 실제 도입 여부·정확한 사거리는 별도 확인 필요).', '양주시 남면', 37.896469, 126.979839),
(5, '제3포병여단', 'K-239 천무', '다연장로켓', '130mm 무유도미사일', 36.00, 50.00, 10, '[\"차량표적\"]', '130mm 로켓(K33 사거리연장탄) 기준 사거리 36km.', '강원도 인제군', 38.066614, 128.250756),
(6, '제3포병여단', 'K-239 천무', '다연장로켓', '600mm 탄도미사일', 300.00, 200.00, 10, '[\"기갑표적\", \"지하표적\"]', '600mm 전술지대지유도탄(KTSSM-II 추정) 기준 사거리 약 290km.', '강원도 인제군', 38.066614, 128.250756);
